mapper.select:
SELECT 0 AS CTR_SEQ,
       c.SSPS_DL_CRT_DT, c.SSPS_DL_ID, c.SSPS_TYP_CD,
       c.DL_P_RNMCNO, c.RPR_PRGRS_CCD, c.INST_ID,
       c.REG_ID, c.REG_DT, c.UPD_ID, c.UPD_DT,
       COALESCE(a.DL_AMT, 0) AS DL_AMT,
       COALESCE(a.DL_CCY, 'KRW') AS DL_CCY
FROM NIC66B c
LEFT JOIN (
    SELECT SSPS_DL_CRT_DT, SSPS_DL_ID,
           SUM(DL_AMT) AS DL_AMT, MAX(DL_CCY) AS DL_CCY
    FROM NIC75B GROUP BY SSPS_DL_CRT_DT, SSPS_DL_ID
) a ON a.SSPS_DL_CRT_DT = c.SSPS_DL_CRT_DT AND a.SSPS_DL_ID = c.SSPS_DL_ID
WHERE c.SSPS_DL_CRT_CCD = 'CTR'

    AND c.RPR_PRGRS_CCD = #{ctrStCd}


    AND c.DL_P_RNMCNO = #{custNo}


    AND c.SSPS_DL_CRT_DT >= #{trxnDtFrom}


    AND c.SSPS_DL_CRT_DT <= #{trxnDtTo}

ORDER BY c.REG_DT DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM NIC66B c
WHERE c.SSPS_DL_CRT_CCD = 'CTR'

    AND c.RPR_PRGRS_CCD = #{ctrStCd}


    AND c.DL_P_RNMCNO = #{custNo}


    AND c.SSPS_DL_CRT_DT >= #{trxnDtFrom}


    AND c.SSPS_DL_CRT_DT <= #{trxnDtTo}
